/* Kurryculum Calorie Calculator + Recipes — page loader (v2, mobile-tuned)
 * Injects the self-contained calculator into an isolated <iframe srcdoc> so
 * styles never leak onto the page and no cross-origin frame can be blocked.
 * Place an empty <div id="kurry-calc"></div> where you want it (or it appends to body).
 */
(function () {
  var B64 = "";
  function decode(b64){
    var bin = atob(b64), len = bin.length, bytes = new Uint8Array(len);
    for (var i=0;i<len;i++) bytes[i]=bin.charCodeAt(i);
    return new TextDecoder("utf-8").decode(bytes);
  }
  function mount(){
    var host = document.getElementById("kurry-calc");
    if(!host){ host = document.createElement("div"); host.id="kurry-calc"; document.body.appendChild(host); }
    var f = document.createElement("iframe");
    f.title = "Kurryculum Calorie Calculator + Cultural Recipes";
    f.setAttribute("loading","lazy");
    f.style.cssText = "width:100%;border:0;display:block;min-height:1400px";
    f.srcdoc = decode(B64);
    host.innerHTML = "";
    host.appendChild(f);
    window.addEventListener("message", function(e){
      if (e && e.data && e.data.kcHeight){ f.style.height = e.data.kcHeight + "px"; }
    });
  }
  if (document.readyState === "loading"){ document.addEventListener("DOMContentLoaded", mount); }
  else { mount(); }
})();
